/** One survival/fluency reflex card (say the English from the Korean cue). */
export interface ReflexCard {
  key: string; // SRS card key, e.g. "iv:rfx:clarify#0"
  cue: string; // 직독직해 — Korean in English word order, " · "-chunked (production scaffold)
  meaning: string; // natural Korean meaning (for the shadow/encode mode)
  model: string; // English model to say
  core: boolean; // one of the ~18 must-be-automatic survival reflexes
}

export interface ReflexCluster {
  id: string;
  labelEn: string;
  labelKo: string;
  cards: ReflexCard[];
}

/** A concept / narration-frame / situational-scenario speaking card. */
export interface InterviewCard {
  key: string; // SRS card key, e.g. "iv:cpt:idempotency"
  group: "concept" | "frame" | "scenario";
  sub?: string; // scenarios: "interview" | "pair"
  title: string; // concept name / the frame / the situation trigger
  cue: string; // Korean prompt
  model: string; // model English answer
  note?: string;
  concepts?: string[];
}

